files.modules/widget/terraform.tf:
terraform {
  required_version = ">= 1.10"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0, < 6.0"
    }
  }
}

files.modules/widget/variables.tf:
variable "name" {
  description = "Name the module's resources derive theirs from."
  type        = string
}

files.modules/widget/outputs.tf:
output "security_group_id" {
  description = "ID of the widget security group."
  value       = aws_security_group.main.id
}

